// ── V2.1.9: Sound (Web Audio beep) ────────────────────────
const SOUND_KEY='horatad_sound_v1';
const SOUND_ICONS=['🔇','🔈','🔉','🔉','🔊','🔊'];
function _initSound(){
  const stored=localStorage.getItem(SOUND_KEY);
  const v=parseInt(stored,10);
  _soundLevel=(!isNaN(v)&&v>=0&&v<=5)?v:1;
  _updateSoundBtn();
}
function _updateSoundBtn(){
  const btn=document.getElementById('sound-btn');
  if(btn)btn.textContent=SOUND_ICONS[_soundLevel]+' เสียง';
}
function cycleSoundLevel(){
  _soundLevel=(_soundLevel+1)%6;
  try{localStorage.setItem(SOUND_KEY,String(_soundLevel));}catch{}
  _updateSoundBtn();
  if(_soundLevel>0)_playBeep(800);
}
function _playBeep(freq){
  if(_soundLevel===0)return;
  try{
    if(!_audioCtx)_audioCtx=new (window.AudioContext||window.webkitAudioContext)();
    if(_audioCtx.state==='suspended')_audioCtx.resume();
    const ac=_audioCtx;
    const osc=ac.createOscillator();
    const gain=ac.createGain();
    const g=_soundLevel*0.08;
    osc.type='sine';
    osc.frequency.value=freq||700;
    gain.gain.setValueAtTime(g,ac.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001,ac.currentTime+0.04);
    osc.connect(gain);gain.connect(ac.destination);
    osc.start();
    osc.stop(ac.currentTime+0.05);
  }catch{}
}

// ── V2.2.23: Long-press name field → ลบทั้ง record ────────
let _nameLpTimer=null;
function _initLongPress(){
  ['1','2'].forEach(sec=>{
    const el=document.getElementById(`name-${sec}`);
    if(!el)return;
    el.addEventListener('pointerdown',()=>{
      _nameLpTimer=setTimeout(()=>{
        _nameLpTimer=null;
        _clearSection(sec);
        _showToast(`ล้างดวงที่ ${sec} แล้ว`);
        if(navigator.vibrate)navigator.vibrate(80);
        _playBeep(500);
      },1000);
    });
    const cancel=()=>{if(_nameLpTimer){clearTimeout(_nameLpTimer);_nameLpTimer=null;}};
    el.addEventListener('pointerup',cancel);
    el.addEventListener('pointerleave',cancel);
    el.addEventListener('pointermove',cancel);
  });
}
function _clearSection(sec){
  ['name','d','m','y','t'].forEach(f=>{
    const id=f==='name'?`name-${sec}`:`${f}${sec}`;
    const el=document.getElementById(id);
    if(el)el.value='';
  });
  if(sec==='1'){
    document.getElementById('prov1').value='กรุงเทพมหานคร';
    document.getElementById('gender1').value='ชาย';
    _customLng1=null;_applyInputColors('1','init');
  }else{
    document.getElementById('prov2').value='กรุงเทพมหานคร';
    document.getElementById('gender2').value='ชาย';
    _customLng2=null;_applyInputColors('2','init');
  }
}

function _showToast(msg,warn){
  const t=document.getElementById('toast');
  if(!t)return;
  t.textContent=msg;
  t.classList.toggle('toast-warn',!!warn);
  t.classList.add('toast-show');
  if(_toastTimer)clearTimeout(_toastTimer);
  _toastTimer=setTimeout(()=>t.classList.remove('toast-show'),2200);
}

// V2.2.32: showAlert/closeAlert — popup ค้างกระพริบ tap-backdrop-to-dismiss
function showAlert(msg,type){
  closeAlert();
  const overlay=document.createElement('div');
  overlay.className='alert-overlay';
  overlay.id='_alertOverlay';
  const popup=document.createElement('div');
  popup.className='alert-popup'+(type==='success'?' alert-success':'');
  popup.textContent=msg;
  overlay.appendChild(popup);
  overlay.addEventListener('click',e=>{if(e.target===overlay)closeAlert();});
  popup.addEventListener('click',e=>e.stopPropagation());
  document.body.appendChild(overlay);
}
function closeAlert(){
  const ov=document.getElementById('_alertOverlay');
  if(ov)ov.remove();
}

// V2.2.33: clearForm(section) + _updateDbIndicator(section)
function clearForm(section){
  const s=String(section);
  const ids=[`name-${s}`,`d${s}`,`m${s}`,`y${s}`,`t${s}`,`prov${s}`];
  ids.forEach(id=>{const el=document.getElementById(id);if(el)el.value=(id==='prov'+s?'กรุงเทพมหานคร':'');});
  const g=document.getElementById('gender'+s);if(g)g.value='ชาย';
  if(s==='1')_customLng1=null;else if(s==='2')_customLng2=null;
  _updateLngUI(s);
  _updateDbIndicator(s);
  if(typeof _chartTags!=='undefined'){_chartTags[s]=[];if(typeof _renderTagRow==='function')_renderTagRow(s);}
}
function _updateDbIndicator(section){
  const s=String(section);
  const indicator=document.getElementById('db-indicator-'+s);
  if(!indicator)return;
  const name=(document.getElementById('name-'+s)||{}).value||'';
  const d=(document.getElementById('d'+s)||{}).value||'';
  const m=(document.getElementById('m'+s)||{}).value||'';
  const y=(document.getElementById('y'+s)||{}).value||'';
  const t=(document.getElementById('t'+s)||{}).value||'';
  const p=(document.getElementById('prov'+s)||{}).value||'';
  if(!name||!d||!m||!y||!t||!p){indicator.classList.add('hidden');return;}
  const mem=_loadJSON(MEM_KEY)||[];
  const k=`${name}|${d}/${m}/${y}|${t}|${p}`;
  const found=mem.some(r=>`${r.name}|${r.d}/${r.m}/${r.y_be}|${r.t}|${r.prov}`===k);
  indicator.classList.toggle('hidden',!found);
}
function _wireDbIndicatorListeners(){
  // V2.2.37: ฟัง 'change' ด้วย — native time picker (iOS Safari) ยิง change อย่างเดียว
  ['1','2'].forEach(s=>{
    ['name-'+s,'d'+s,'m'+s,'y'+s,'t'+s,'prov'+s].forEach(id=>{
      const el=document.getElementById(id);
      if(!el)return;
      el.addEventListener('input',()=>_updateDbIndicator(s));
      el.addEventListener('change',()=>_updateDbIndicator(s));
    });
  });
}

// V2.2.34: tag groups (4 per chart) + custom tags + auto-save to DB
const DEFAULT_TAGS=['ตัวอย่าง','เพื่อน','ครอบครัว','ลูกค้า'];
const CUSTOM_TAGS_KEY='horatad_custom_tags';
const MAX_GROUPS_PER_CHART=4;
let _chartTags={'1':[],'2':[]};
let _addTagSection=null;
function _loadCustomTags(){return _loadJSON(CUSTOM_TAGS_KEY)||[];}
function _saveCustomTags(arr){_saveJSON(CUSTOM_TAGS_KEY,arr.slice(0,32));}
function _allTags(){
  const custom=_loadCustomTags();
  const merged=DEFAULT_TAGS.slice();
  custom.forEach(t=>{if(!merged.includes(t))merged.push(t);});
  return merged;
}
function _renderTagRow(section){
  const row=document.getElementById('tag-row-'+section);
  if(!row)return;
  row.innerHTML='';
  // Phase 3: transit mode → tag-row-1 แสดง linked event chips
  if(section==='1'&&_reportTransitShow){
    const evs=natal1?.uid?_dbEvents(natal1.uid):[];
    if(evs.length){
      evs.forEach(s=>{
        const chip=document.createElement('span');
        chip.className='tag-chip tag-event-chip';
        chip.textContent='🔗 '+(s.name||'—');
        chip.title=`${s.d||''}/${s.m||''}/${s.y_be||''} · ${s.t||''} — คลิกโหลด`;
        chip.addEventListener('click',()=>_eventSlotLoadByUid(s.uid));
        row.appendChild(chip);
      });
    }else{
      const ph=document.createElement('span');
      ph.className='tag-chip';
      ph.style.cssText='color:#444;cursor:default;background:transparent;border-color:#2a2a2e';
      ph.textContent='ยังไม่มีเหตุการณ์';
      row.appendChild(ph);
    }
    const addBtn=document.createElement('span');
    addBtn.className='tag-chip-add';
    addBtn.textContent='+ เหตุการณ์';
    addBtn.addEventListener('click',()=>_openEventSlotsPopup());
    row.appendChild(addBtn);
    return;
  }
  // ปกติ: category tags
  const tags=_allTags();
  const active=_chartTags[section]||[];
  const isCustom=name=>!DEFAULT_TAGS.includes(name);
  tags.forEach(name=>{
    const chip=document.createElement('span');
    chip.className='tag-chip'+(active.includes(name)?' tag-active':'');
    if(isCustom(name)){
      chip.innerHTML=`<span>${_escHtml(name)}</span><button class="tag-chip-del" title="ลบ tag" onclick="event.stopPropagation();_deleteCustomTag('${_escHtml(name)}')">✕</button>`;
      chip.querySelector('span').addEventListener('click',()=>_toggleTag(section,name));
    }else{
      chip.textContent=name;
      chip.addEventListener('click',()=>_toggleTag(section,name));
    }
    row.appendChild(chip);
  });
  const addBtn=document.createElement('span');
  addBtn.className='tag-chip-add';
  addBtn.textContent='+ เพิ่ม';
  addBtn.addEventListener('click',()=>_openAddTagModal(section));
  row.appendChild(addBtn);
}
function _eventSlotLoadByUid(uid){
  if(!uid)return;
  const s=_dbFind(uid);
  if(s&&s.type==='event')_eventSlotLoadRecord(s);
}
function _toggleTag(section,name){
  const arr=_chartTags[section]||(_chartTags[section]=[]);
  const idx=arr.indexOf(name);
  if(idx>=0){arr.splice(idx,1);}
  else{
    if(arr.length>=MAX_GROUPS_PER_CHART){_showToast(`เลือกได้สูงสุด ${MAX_GROUPS_PER_CHART} กลุ่ม/dวง`,true);return;}
    arr.push(name);
  }
  _renderTagRow(section);
  _saveTagsToMemory(section);
}
function _saveTagsToMemory(section){
  const s=String(section);
  const name=(document.getElementById('name-'+s)||{}).value||'';
  const d=(document.getElementById('d'+s)||{}).value||'';
  const m=(document.getElementById('m'+s)||{}).value||'';
  const y=(document.getElementById('y'+s)||{}).value||'';
  const t=(document.getElementById('t'+s)||{}).value||'';
  const p=(document.getElementById('prov'+s)||{}).value||'';
  if(!name||!d||!m||!y||!t||!p)return;
  const key=`${name}|${d}/${m}/${y}|${t}|${p}`;
  const mem=_loadJSON(MEM_KEY)||[];
  const i=mem.findIndex(r=>`${r.name}|${r.d}/${r.m}/${r.y_be}|${r.t}|${r.prov}`===key);
  if(i<0)return;
  mem[i].groups=(_chartTags[s]||[]).slice();
  mem[i].savedAt=Date.now();
  _saveJSON(MEM_KEY,mem);
}
function _openAddTagModal(section){
  _addTagSection=String(section);
  const modal=document.getElementById('add-tag-modal');
  const input=document.getElementById('add-tag-input');
  if(input){input.value='';setTimeout(()=>input.focus(),50);}
  if(modal)modal.classList.remove('hidden');
}
function _closeAddTagModal(){
  const modal=document.getElementById('add-tag-modal');
  if(modal)modal.classList.add('hidden');
  _addTagSection=null;
}
function _submitAddTag(){
  const input=document.getElementById('add-tag-input');
  const name=(input&&input.value||'').trim().slice(0,20);
  if(!name){_showToast('ใส่ชื่อ tag ก่อน',true);return;}
  const custom=_loadCustomTags();
  if(_allTags().includes(name)){
    // already exists — เลือก tag นั้นแทน
    if(_addTagSection&&!(_chartTags[_addTagSection]||[]).includes(name)){
      _toggleTag(_addTagSection,name);
    }
  }else{
    custom.push(name);
    _saveCustomTags(custom);
    if(_addTagSection){_toggleTag(_addTagSection,name);}
  }
  _closeAddTagModal();
  if(_addTagSection)_renderTagRow(_addTagSection);
}
function _deleteCustomTag(name){
  _saveCustomTags(_loadCustomTags().filter(t=>t!==name));
  ['1','2'].forEach(s=>{
    if(_chartTags[s]){const i=_chartTags[s].indexOf(name);if(i>=0){_chartTags[s].splice(i,1);_saveTagsToMemory(s);}}
    _renderTagRow(s);
  });
}
function _loadTagsForCurrentChart(section){
  const s=String(section);
  const name=(document.getElementById('name-'+s)||{}).value||'';
  const d=(document.getElementById('d'+s)||{}).value||'';
  const m=(document.getElementById('m'+s)||{}).value||'';
  const y=(document.getElementById('y'+s)||{}).value||'';
  const t=(document.getElementById('t'+s)||{}).value||'';
  const p=(document.getElementById('prov'+s)||{}).value||'';
  if(!name||!d||!m||!y||!t||!p){_chartTags[s]=[];return;}
  const key=`${name}|${d}/${m}/${y}|${t}|${p}`;
  const mem=_loadJSON(MEM_KEY)||[];
  const rec=mem.find(r=>`${r.name}|${r.d}/${r.m}/${r.y_be}|${r.t}|${r.prov}`===key);
  _chartTags[s]=(rec&&Array.isArray(rec.groups))?rec.groups.slice():[];
}

