function _buildShareFilename(active){
  const jd=Math.trunc(_calcJD(active.d,active.m,active.y_be));
  const t=(active.t||'').replace(':','');
  const lat=(PROVINCES_LAT[active.prov||'']||13.75).toFixed(2);
  return `${jd}_${t}_${lat}.png`;
}

async function saveChart(){
  const active=_viewMode===1?_chart2:natal1;
  if(!active)return;
  _playShutter();
  const blob=await _generateShareImage(active);
  if(!blob){_showToast('ไม่สามารถสร้างรูปได้',true);return;}
  const filename=_buildShareFilename(active);
  const file=new File([blob],filename,{type:'image/png'});
  if(navigator.canShare&&navigator.canShare({files:[file]})){
    try{
      await navigator.share({files:[file],title:'ดวงชะตา Horatad'});
      return;
    }catch(e){if(e.name==='AbortError')return;}
  }
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=filename;
  document.body.appendChild(a);a.click();
  document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(url),1000);
  _showToast('บันทึกรูปแล้ว');
}

async function shareChart(){
  const active=_viewMode===1?_chart2:natal1;
  if(!active)return;
  _playShutter();
  const blob=await _generateShareImage(active);
  if(!blob){_showToast('ไม่สามารถสร้างรูปได้',true);return;}
  const filename=_buildShareFilename(active);
  const file=new File([blob],filename,{type:'image/png'});
  if(navigator.canShare&&navigator.canShare({files:[file]})){
    try{
      await navigator.share({files:[file],title:'ดวงชะตา Horatad',text:`${active.name} ${active.d}/${active.m}/${active.y_be}`});
      return;
    }catch(e){
      if(e.name==='AbortError')return;
      // fall through to download fallback
    }
  }
  // Fallback: download
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=filename;
  document.body.appendChild(a);a.click();
  document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(url),1000);
  _showToast('เบราว์เซอร์ไม่รองรับแชร์ — บันทึกไฟล์แทน');
}

// ── H2 QR signing (HMAC-SHA256, L2 security) ─────────────
const H2_SECRET='HTD-H2-2026-K1';
async function _hmac8(data){
  const enc=new TextEncoder();
  const key=await crypto.subtle.importKey('raw',enc.encode(H2_SECRET),{name:'HMAC',hash:'SHA-256'},false,['sign']);
  const sig=await crypto.subtle.sign('HMAC',key,enc.encode(data));
  return Array.from(new Uint8Array(sig)).slice(0,4).map(b=>b.toString(16).padStart(2,'0')).join('');
}
async function _verifyH2(dataStr,hmac){
  try{return(await _hmac8(dataStr))===hmac;}catch{return false;}
}

// V2.2.24: load qrcode.js on-demand (not in CORE_ASSETS)
async function _loadQRLib(){
  if(window.QRCode)return;
  await new Promise((res,rej)=>{
    const s=document.createElement('script');
    s.src='https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js';
    s.onload=res;s.onerror=rej;
    document.head.appendChild(s);
  });
}

async function _generateShareImage(active){
  if(document.fonts&&document.fonts.ready)await document.fonts.ready;
  const SZ=1080;
  const c=document.createElement('canvas');
  c.width=SZ;c.height=SZ;
  const ctx=c.getContext('2d');
  ctx.fillStyle=BG_V1;
  ctx.fillRect(0,0,SZ,SZ);
  // chart top — bottom y=820
  const chart=document.getElementById('chart-canvas');
  const chartSize=780;
  const chartX=(SZ-chartSize)/2;
  ctx.drawImage(chart,chartX,40,chartSize,chartSize);
  const y_ce=_beToce(active.y_be,active.m);
  // Right column — 4 lines, right-aligned x=SZ-30
  const INFO_X=SZ-30;
  ctx.textAlign='right';ctx.textBaseline='top';
  ctx.fillStyle='#ffffff';
  ctx.font='bold 32px Sarabun,sans-serif';
  ctx.fillText((active.name||'').slice(0,20),INFO_X,835);
  ctx.fillStyle='#8b949e';
  ctx.font='400 22px Sarabun,sans-serif';
  ctx.fillText(`${active.d}/${active.m}/${active.y_be} (${y_ce})`,INFO_X,875);
  ctx.fillText(active.t||'',INFO_X,901);
  ctx.fillText(active.prov||'',INFO_X,927);
  // Score center top-aligned at y=835 (edge level with name first line)
  const asc=Math.trunc(active.pos[0]/1800);
  let total=0;
  for(let i=1;i<=8;i++)total+=getStrength(active.pos,active.vel,i,asc)[0];
  const scoreColor=total>=5?'#2ea043':total>=-5?'#b8860b':'#f85149';
  const scoreLabel=total>=15?'ดวงชะตาแข็งแกร่งโดยรวม 🌟':total>=5?'ดวงชะตาระดับปานกลาง ⭐':total>=-5?'ดวงชะตาที่ต้องระวัง ⚠️':'ดวงชะตาที่อ่อนแอ ❌';
  ctx.textAlign='center';
  ctx.fillStyle=scoreColor;
  ctx.font='bold 64px Sarabun,sans-serif';
  ctx.fillText((total>=0?'+':'')+total,SZ/2,835);
  // scoreLabel center under score
  ctx.fillStyle='#c9d1d9';
  ctx.font='500 22px Sarabun,sans-serif';
  ctx.fillText(scoreLabel,SZ/2,905);
  // horatad.com center, smaller, level with prov line (Sarabun → lowercase render)
  ctx.fillStyle='#888888';
  ctx.font='500 13px Sarabun,sans-serif';
  ctx.fillText('horatad.com',SZ/2,933);
  // QR bottom-left — top-left corner คงเดิม (28, 820), ขยาย 125→250, bottom y=1070
  try{
    await _loadQRLib();
    const jd=Math.trunc(_calcJD(active.d,active.m,active.y_be));
    const lng=(typeof active.lng==='number'?active.lng:100.50).toFixed(2);
    const lat=(typeof active.lat==='number'?active.lat:(PROVINCES_LAT[active.prov||'']||13.75)).toFixed(2);
    const g=(active.gender||'').charAt(0)||'?';
    const nm=(active.name||'').slice(0,20);
    const dataStr=`${jd}|${active.t||''}|${lat}|${lng}|${g}|${nm}`;
    const hmac=await _hmac8(dataStr);
    const qrText=`https://horatad.github.io/horatad/?h=H2|${hmac}|${dataStr}`;
    const qrDiv=document.createElement('div');
    qrDiv.style.cssText='position:fixed;left:-9999px;top:-9999px';
    document.body.appendChild(qrDiv);
    // V2.2.42: ECC H → M เพราะ Thai UTF-8 (3 bytes/char) ทำ payload โต → H overflow
    new QRCode(qrDiv,{text:qrText,width:250,height:250,colorDark:'#000000',colorLight:'#ffffff',correctLevel:typeof QRCode!=='undefined'&&QRCode.CorrectLevel?QRCode.CorrectLevel.M:undefined});
    // iOS Safari: qrcodejs creates <img> not <canvas> — wait for onload
    await new Promise(res=>{
      const img=qrDiv.querySelector('img');
      if(img){
        if(img.complete&&img.naturalWidth>0)return res();
        img.onload=res;img.onerror=res;
        setTimeout(res,1000);
      }else{
        setTimeout(res,200);
      }
    });
    const qrEl=qrDiv.querySelector('canvas')||qrDiv.querySelector('img');
    if(qrEl)ctx.drawImage(qrEl,28,820,250,250);
    document.body.removeChild(qrDiv);
  }catch(e){console.warn('[QR]',e);}
  return new Promise(resolve=>c.toBlob(resolve,'image/png',0.95));
}

