function _numpadKey(k){
  const id=_numpadField?(_numpadField.id||''):'';
  const isLng=(id==='lng1'||id==='lng2'||id==='lngt');
  const cfg=isLng?{type:'lng'}:(_NUMPAD_CFG[id]||{type:'int',min:1,max:9999,def:1});
  const mx=isLng?5:(cfg.type==='time'?4:String(cfg.max||9999).length);
  if(k==='ล้าง'){_numpadBuf='';_playBeep(550);}
  else if(k==='✓'){_playBeep(900);_numpadConfirm();return;}
  else{if(_numpadBuf.length<mx){_numpadBuf+=k;_playBeep(700);}}
  let disp=_numpadBuf||'—';
  if(isLng){
    // [V1.9] left-to-right display "_ _ _ . _ _" matches user mental model
    if(_numpadBuf.length===0){
      disp='_ _ _ . _ _';
    }else{
      let s=_numpadBuf;
      let intPart=s.slice(0,3).padEnd(3,'_').split('').join(' ');
      let decPart=s.slice(3,5).padEnd(2,'_').split('').join(' ');
      disp=intPart+' . '+decPart;
    }
  }else if(cfg.type==='time'&&_numpadBuf.length>=3){
    disp=_numpadBuf.slice(0,2)+':'+_numpadBuf.slice(2);
  }
  document.getElementById('numpad-display').textContent=disp;
  _updatePre2484Warning();
}
// V2.1.9: validate buffer on confirm; revert to prev value after 3 invalid attempts
function _numpadConfirm(){
  if(_numpadField&&_numpadBuf){
    const id=_numpadField.id||'';
    const isLng=(id==='lng1'||id==='lng2'||id==='lngt');
    let invalid=false;
    if(isLng){
      let s=_numpadBuf.padEnd(5,'0');
      let intPart=parseInt(s.slice(0,3))||0;
      let decPart=parseInt(s.slice(3,5))||0;
      let lng=intPart+decPart/100;
      if(lng>=0&&lng<=180){
        if(id==='lng1')_customLng1=lng;
        else if(id==='lng2')_customLng2=lng;
        else _customLngT=lng;
        const cn=id==='lng1'?'1':id==='lng2'?'2':'t';
        _updateLngUI(cn);
      }else{
        invalid=true;
      }
    }else{
      const cfg=_NUMPAD_CFG[id]||{type:'int',min:1,max:9999,def:1};
      // [V1.9] year smart prefix: BE="25"+2 digits, CE="20"+2 digits
      let buf=_numpadBuf;
      if((id==='y1'||id==='y2'||id==='yt')&&buf.length===2){
        buf=(_era==='BE'?'25':'20')+buf;
      }
      let n=parseInt(buf);
      if(isNaN(n)||n<cfg.min||n>cfg.max){
        invalid=true;
      }else{
        _setField(id,String(n));
      }
    }
    if(invalid){
      _numpadInvalidCount++;
      _playBeep(380);
      if(_numpadInvalidCount>=3){
        // Revert to last valid value
        if(isLng){
          // clear custom lng (revert to province)
          if(id==='lng1')_customLng1=null;
          else if(id==='lng2')_customLng2=null;
          else _customLngT=null;
          const cn=id==='lng1'?'1':id==='lng2'?'2':'t';
          _updateLngUI(cn);
          _showToast(`ผิด 3 ครั้ง — ใช้ลองติจูดจังหวัด`,true);
        }else{
          _setField(id,_numpadPrevValue);
          _showToast(`ผิด 3 ครั้ง — ใช้ค่าเดิม: ${_numpadPrevValue||'—'}`,true);
        }
      }else{
        // Allow another attempt — don't close numpad
        _showToast(`ค่าไม่ถูกต้อง (${_numpadInvalidCount}/3)`,true);
        _numpadBuf='';
        const dispEl=document.getElementById('numpad-display');
        if(dispEl)dispEl.textContent=isLng?'_ _ _ . _ _':'—';
        return; // KEEP numpad open
      }
    }
  }
  // V2.2.37: numpad commit (d/m/y/lng) ไม่ fire 'input' event → ปลุก DB indicator เอง
  if(_numpadField){
    const cid=_numpadField.id||'';
    const sec=cid.slice(-1);
    if((sec==='1'||sec==='2')&&typeof _updateDbIndicator==='function'){
      _updateDbIndicator(sec);
    }
  }
  _numpadBuf='';
  document.getElementById('numpad').classList.add('hidden');
  document.getElementById('numpad-backdrop').classList.add('hidden');
  const warn=document.getElementById('numpad-warning');
  if(warn)warn.classList.add('hidden');
  _numpadField=null;
}

// ── localStorage persistence ──────────────────────────────
const STATE_KEY='horatad_state_v1';
const MEM_KEY='horatad_memory_v1';
const MEM_MAX=200;
const EVENT_KEY='horatad_events_v1';
const EVENT_MAX=20;
const PROMPTPAY_ID='3102001951829';
const PROMPTPAY_NAME='นายสิทธิเดช ประเสริฐรุ่งเรือง';

function _loadJSON(k){try{return JSON.parse(localStorage.getItem(k));}catch{return null;}}
function _saveJSON(k,v){try{localStorage.setItem(k,JSON.stringify(v));}catch{}}

// ── V4 Unified Storage Layer ──────────────────────────────
// type: 'natal' | 'person' | 'event' | 'group'
// natal:  { uid, type, name, gender, d, m, y_be, t, prov, lat, lng, jd, pos, vel, savedAt }
// person: { uid, type, ..., linkedNatalUid }   — สมพงศ์ / คนเปรียบเทียบ
// event:  { uid, type, ..., linkedNatalUid }   — เหตุการณ์จร
// group:  { uid, type, name, memberUids[], savedAt }
const SCHEMA_VERSION=4;
const SCHEMA_VERSION_KEY='horatad_schema_v';
const DB_KEY='horatad_db_v4';
const MIGRATION_NOTICE_KEY='horatad_v4_notice_shown';

function _migrateSchemaV4(){
  const cur=parseInt(localStorage.getItem(SCHEMA_VERSION_KEY)||'0',10);
  if(cur>=SCHEMA_VERSION)return false;
  const unified=[];const seen=new Set();
  const add=(r,type,extra={})=>{
    if(!r||seen.has(r.uid))return;
    const uid=r.uid||crypto.randomUUID();
    seen.add(uid);
    const clean={...r,...extra,type,uid};
    delete clean.linkedEvents;delete clean.linkedNatal;
    if(type!=='person'&&type!=='event')delete clean.linkedNatalUid;
    unified.push(clean);
  };
  (_loadJSON('horatad_db1_v3')||[]).forEach(r=>add(r,'natal'));
  (_loadJSON('horatad_buffer_v3')||[]).forEach(r=>add(r,'person',{linkedNatalUid:null}));
  (_loadJSON('horatad_event_slots_v3')||[]).forEach(r=>add(r,'event',{linkedNatalUid:r.linkedNatalUid||null}));
  (_loadJSON('horatad_db2_v3')||[]).forEach(r=>add(r,'event',{linkedNatalUid:r.linkedNatal||null}));
  if(unified.length)_saveJSON(DB_KEY,unified);
  localStorage.setItem(SCHEMA_VERSION_KEY,String(SCHEMA_VERSION));
  ['horatad_memory_v1','horatad_events_v1','horatad_db1_v3','horatad_db2_v3',
   'horatad_buffer_v3','horatad_event_slots_v3'].forEach(k=>localStorage.removeItem(k));
  console.log('[V4] unified DB migrated:',unified.length,'records');
  return cur>0||unified.length>0;
}
const _v4Migrated=_migrateSchemaV4();

// ── Core DB CRUD ──────────────────────────────────────────
function _dbLoad(){return _loadJSON(DB_KEY)||[];}
function _dbSave(arr){_saveJSON(DB_KEY,arr);}
function _dbFind(uid){return _dbLoad().find(r=>r.uid===uid)||null;}
function _dbRemove(uid){_dbSave(_dbLoad().filter(r=>r.uid!==uid));}
function _dbUpsert(rec){
  const db=_dbLoad();
  const i=db.findIndex(r=>r.uid===rec.uid);
  if(i>=0)db[i]=rec;else db.unshift(rec);
  _dbSave(db);return rec;
}
function _dbLoadType(type){return _dbLoad().filter(r=>r.type===type);}
function _dbSaveType(type,arr){
  const others=_dbLoad().filter(r=>r.type!==type);
  _dbSave([...arr,...others]);
}

