function _exportDB(){
  const payload={
    _id:'HORATAD:EXPORT',v:APP_VERSION,
    exportedAt:new Date().toISOString(),
    db:_dbLoad()
  };
  const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;
  a.download=`horatad_export_${new Date().toISOString().slice(0,10)}.json`;
  a.click();URL.revokeObjectURL(url);
  _showToast('ส่งออกข้อมูลแล้ว');
}
function _importDB(input){
  const file=input?.files?.[0];
  if(!file)return;
  const reader=new FileReader();
  reader.onload=e=>{
    try{
      const data=JSON.parse(e.target.result);
      if(data._id!=='HORATAD:EXPORT')throw new Error('ไฟล์ไม่ถูกต้อง');
      let added=0;
      const db=_dbLoad();
      const existingUids=new Set(db.map(r=>r.uid));
      // รองรับ format ใหม่ (db[]) และเก่า (db1[]+eventSlots[])
      const incoming=[
        ...(Array.isArray(data.db)?data.db:[]),
        ...(Array.isArray(data.db1)?data.db1.map(r=>({...r,type:r.type||'natal'})):[]),
        ...(Array.isArray(data.eventSlots)?data.eventSlots.map(r=>({...r,type:r.type||'event'})):[])
      ];
      for(const rec of incoming){
        if(!rec.uid||existingUids.has(rec.uid))continue;
        existingUids.add(rec.uid);
        db.unshift(rec);added++;
      }
      _dbSave(db);
      // ตรวจ orphan events
      const natalUids=new Set(_dbLoadType('natal').map(r=>r.uid));
      const orphans=_dbEvents().filter(s=>s.linkedNatalUid&&!natalUids.has(s.linkedNatalUid)).length;
      const orphanNote=orphans?` · ⚠️ เหตุการณ์ ${orphans} รายการ link กับดวงที่ไม่มีใน DB`:'';
      const msg=`นำเข้าสำเร็จ: +${added} รายการ${orphanNote}`;
      document.getElementById('import-result').textContent=msg;
      _updateMainMenuState();_showToast(msg);
    }catch(err){
      document.getElementById('import-result').textContent='⚠️ '+err.message;
      _showToast('นำเข้าไม่สำเร็จ: '+err.message,true);
    }
  };
  reader.readAsText(file);
}

// ── QR Import (Phase 4) ──────────────────────────────────
function _jdToGregorian(customJd){
  const jdn=Math.round(customJd)+1721117;
  const a=jdn+32044;
  const b=Math.floor((4*a+3)/146097);
  const c=a-Math.floor(146097*b/4);
  const dv=Math.floor((4*c+3)/1461);
  const e=c-Math.floor(1461*dv/4);
  const mv=Math.floor((5*e+2)/153);
  return{
    d:e-Math.floor((153*mv+2)/5)+1,
    m:mv+3-12*Math.floor(mv/10),
    y_ce:100*b+dv-4800+Math.floor(mv/10)
  };
}
function _latLngToProv(lat,lng){
  let best='กรุงเทพมหานคร',bestDist=Infinity;
  for(const[prov,platLat]of Object.entries(PROVINCES_LAT)){
    const plng=PROVINCES[prov];
    if(plng==null)continue;
    const dist=(lat-platLat)**2+(lng-plng)**2;
    if(dist<bestDist){bestDist=dist;best=prov;}
  }
  return best;
}
function _parseH1Payload(raw){
  const s=(raw||'').trim();
  let payload=s;
  if(s.includes('?')){
    try{const u=new URL(s.startsWith('http')?s:'https://x/?'+s.split('?')[1]);payload=u.searchParams.get('h')||s;}catch{}
  }
  const parts=payload.split('|');
  let ver='H1',hmac=null,dp;
  if(parts[0]==='H2'&&parts.length>=8){ver='H2';hmac=parts[1];dp=parts.slice(2);}
  else if(parts[0]==='H1'&&parts.length>=7){ver='H1';dp=parts.slice(1);}
  else return null;
  const jd=parseInt(dp[0],10);
  if(!jd||isNaN(jd))return null;
  const{d,m,y_ce}=_jdToGregorian(jd);
  const lat=parseFloat(dp[2]),lng=parseFloat(dp[3]);
  if(isNaN(lat)||isNaN(lng))return null;
  const prov=_latLngToProv(lat,lng);
  const gMap={'ช':'ชาย','ห':'หญิง','เ':'เหตุการณ์'};
  const gender=gMap[dp[4]]||'ชาย';
  const name=(dp[5]||'').trim().slice(0,20)||'ไม่ระบุ';
  return{name,gender,d,m,y_be:y_ce+543,t:dp[1]||'00:00',lat,lng,prov,
    _ver:ver,_hmac:hmac,_dataStr:dp.join('|')};
}
function _fillFormFromImport(data){
  if(!data)return false;
  _era='BE';
  _applyEraStyle();
  _setField('name-1',data.name);
  document.getElementById('gender1').value=data.gender;
  _setField('d1',data.d);
  _setField('m1',data.m);
  _setField('y1',data.y_be);
  _setField('t1',data.t);
  _setField('prov1',data.prov);
  _customLng1=data.lng;
  return true;
}
function _copyImportUrl(){
  if(!natal1?.pos){_showToast('ผูกดวงก่อน',true);return;}
  _closeMainMenu();
  const jd=Math.trunc(_calcJD(natal1.d,natal1.m,natal1.y_be));
  const lng=(typeof natal1.lng==='number'?natal1.lng:100.50).toFixed(2);
  const lat=(typeof natal1.lat==='number'?natal1.lat:(PROVINCES_LAT[natal1.prov||'']||13.75)).toFixed(2);
  const g=(natal1.gender||'').charAt(0)||'?';
  const nm=(natal1.name||'').slice(0,20);
  const dataStr=`${jd}|${natal1.t||''}|${lat}|${lng}|${g}|${nm}`;
  _hmac8(dataStr).then(hmac=>{
    const url=`https://horatad.github.io/horatad/?h=H2|${hmac}|${dataStr}`;
    navigator.clipboard.writeText(url).then(()=>{
      _showToast('คัดลอก URL แล้ว — วางใน chat/browser เพื่อนำเข้า');
    }).catch(()=>{_showToast('คัดลอกไม่ได้ — ใช้ share image QR แทน',true);});
  });
}
