// ── V2.2.17: Rule Matching ───────────────────────────────
function _matchRules(natal,transit){
  if(!_kbRules||!natal)return[];
  const lagnaSign=Math.trunc(natal.pos[0]/1800);
  const seen=new Set(),res=[];
  const PNAMES=['','อาทิตย์','จันทร์','อังคาร','พุธ','พฤหัส','ศุกร์','เสาร์','ราหู','เกตุ','มฤตยู'];
  const QLABELS={เกษตร:1,ประเกษตร:1,อุจ:1,อุจจาวิลาส:1,อุจจาภิมุข:1,มหาจักร:1,จุลจักร:1,ราชาโชค:1,เทวีโชค:1,นิจ:1};
  function aspSign(planetSign){
    const d=((planetSign-lagnaSign)+12)%12;
    if(d===0)return'กุม';if(d===6)return'เล็ง';
    if(d===2||d===10)return'โยค';if(d===4||d===8)return'ตรีโกณ';
    return'';
  }
  function addRule(r){const k=r.c+r.ch;if(!seen.has(k)){seen.add(k);res.push(r);}}
  // natal planet matching
  // QUAL_MAP: getStandards() return → name_th ใน KB tags (จาก tb_standards)
  const QUAL_MAP={'ประ':'ประเกษตร','มหาอุจ':'อุจ'};
  // SCORE_MAP: จาก tb_standards.score
  const SCORE_MAP={
    'อุจ':5,'เกษตร':4,'มหาจักร':4,'ราชาโชค':3,
    'อุจจาวิลาส':3,'อุจจาภิมุข':3,'จุลจักร':2,'เทวีโชค':2,
    'ประเกษตร':-3,'นิจ':-5
  };
  for(let i=1;i<=10;i++){
    const pName=PNAMES[i]||'มฤตยู';
    const pIdx=i===10?0:i;
    const pSign=Math.trunc(natal.pos[pIdx]/1800);
    const pQualRaw=getStandards(natal.pos,pIdx);
    const pQuals=pQualRaw
      ?pQualRaw.split('/').map(q=>QUAL_MAP[q]||q).filter(q=>QLABELS[q])
      :[];
    const pScore=pQuals.length>0?Math.max(...pQuals.map(q=>SCORE_MAP[q]||0)):0;
    const pIsBad=pScore<0;
    const pIsNormal=pScore===0;
    const pIsGood=pScore>0;
    const asp=aspSign(pSign);
    const hasAsp=asp!=='';
    _kbRules.forEach(r=>{
      const ts=(r.t||[]).join(' ');
      const rtags=r.t||[];
      if(!ts.includes(pName))return;
      // ── Quality gate (AND) ──────────────────────────────────────────
      // ตรวจ quality constraint ของ rule ก่อน
      // ถ้าคุณภาพดาวไม่ตรง → ออกเลย ไม่ต้องดู aspect
      const rBad=rtags.includes('เสีย');
      const rGood=rtags.includes('ดี')||rtags.includes('ดีมาก')||rtags.includes('ดีรอง');
      const rNormal=rtags.includes('ปกติ');
      const rSpecific=rtags.filter(t=>QLABELS[t]);  // เกษตร/อุจ/นิจ/... exact
      if(rBad&&!pIsBad)return;                        // rule ต้องการเสีย แต่ดาวไม่เสีย
      if(rGood&&!pIsGood)return;                      // rule ต้องการดี แต่ดาวไม่ดี
      if(rNormal&&!pIsNormal)return;                  // rule ต้องการปกติ แต่ดาวไม่ปกติ
      if(rSpecific.length>0&&!rSpecific.some(q=>pQuals.includes(q)))return;
      // ── Aspect match (หลัง quality gate ผ่าน) ──────────────────────
      const hasL=ts.includes('ลัคนา');
      const hasNL=ts.includes('ไม่สัมพันธ์ลัคนา');
      if(hasL||hasNL){
        // rule มี aspect constraint
        if(hasAsp&&hasL&&!hasNL)addRule(r);
        if(!hasAsp&&hasNL)addRule(r);
      } else {
        // rule ไม่มี aspect constraint → match ถ้า quality gate ผ่านแล้ว
        addRule(r);
      }
    });
  }
  // transit planet matching
  const tSrc=transit||_chart2;
  if(tSrc){
    for(let i=1;i<=10;i++){
      const pName=PNAMES[i]||'มฤตยู';
      const pIdx=i===10?0:i;
      const pSign=Math.trunc(tSrc.pos[pIdx]/1800);
      const asp=aspSign(pSign);
      if(!asp)continue;
      _kbRules.filter(r=>(r.t||[]).join(' ').includes('จร')&&(r.t||[]).join(' ').includes(pName))
        .forEach(r=>addRule(r));
    }
  }
  // foundation rules
  _kbRules.filter(r=>r.pr===1&&['chapter_04','chapter_06','chapter_08','chapter_09','chapter_13'].includes(r.ch))
    .slice(0,6).forEach(r=>addRule(r));
  res.sort((a,b)=>a.pr-b.pr);
  return res.slice(0,28);
}
// ── V2.2.20: Typhoon AI Interpretation ──────────────────
async function _callTyphoon(natal,transit,matched){
  const rulesText=matched.map(r=>`• ${r.c} → ${r.p}`).join('\n');
  const lagnaIdx=Math.trunc(natal.pos[0]/1800)+1;
  const RNAMES=['เมษ','พฤษภ','มิถุน','กรกฎ','สิงห์','กันย์','ตุลย์','พิจิก','ธนู','มกร','กุมภ์','มีน'];
  const natalInfo=`ลัคนา: ราศี${RNAMES[lagnaIdx-1]||lagnaIdx}`;
  const hasTransit=transit||_chart2;
  const prompt=`คุณเป็นโหรไทยผู้เชี่ยวชาญโหราศาสตร์ไทย กรุณาอ่านกฎพยากรณ์ต่อไปนี้แล้วเรียบเรียงเป็นคำทำนายที่อ่านง่าย เป็นภาษาไทย สั้นกระชับ ไม่เกิน 300 คำ ไม่ต้องระบุหมายเลขดาว\n\nดวงชาตา: ${natal.name}\n${natalInfo}${hasTransit?'\n(มีดวงจร)':''}\n\nกฎที่ตรงกับดวง:\n${rulesText}`;
  const resp=await fetch(WORKER_URL,{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
      model:'typhoon-v2.5-30b-a3b-instruct',
      max_tokens:1000,
      messages:[{role:'user',content:prompt}]
    })
  });
  if(!resp.ok)throw new Error(`HTTP ${resp.status}`);
  const data=await resp.json();
  if(data.choices&&data.choices[0])return data.choices[0].message.content;
  if(data.content&&data.content[0])return data.content[0].text;
  throw new Error(data.error?.message||'Typhoon error');
}
// ── V2.2.17: Interpretation Modal ───────────────────────
async function openInterpretation(){
  // V2.2.23: ทำนายจากดวงวงใน (natal1) เสมอ ไม่ขึ้นกับ viewMode
  const active=natal1;
  if(!active||!_kbRules)return;
  const backdrop=document.getElementById('interp-backdrop');
  const modal=document.getElementById('interp-modal');
  const text=document.getElementById('interp-text');
  const spinner=document.getElementById('interp-spinner');
  const copyBtn=document.getElementById('interp-copy-btn');
  if(!backdrop||!modal)return;
  // show modal + spinner immediately
  backdrop.classList.remove('hidden');
  modal.classList.remove('hidden');
  spinner.classList.remove('hidden');
  text.classList.add('hidden');
  text.textContent='';
  copyBtn.disabled=true;
  const matched=_matchRules(active,_chart2);
  let out='';
  try{
    out=await _callTyphoon(active,_chart2,matched);
  }catch(e){
    console.warn('[Typhoon]',e);
    // fallback: show matched rules grouped by chapter
    const groups={};
    matched.forEach(r=>{
      const grp=r.ct||'ทั่วไป';
      if(!groups[grp])groups[grp]=[];
      groups[grp].push(r);
    });
    let fb=`ดวงชาตา: ${active.name}\nพบ ${matched.length} กฎที่ตรงกับดวง\n`;
    if(_chart2)fb+=`(รวมดาวจร)\n`;
    fb+='\n';
    Object.entries(groups).forEach(([grp,rules])=>{
      fb+=`── ${grp} ──\n`;
      rules.forEach(r=>{fb+=`• ${r.c}\n  → ${r.p}\n\n`;});
    });
    out=fb.trim();
  }
  spinner.classList.add('hidden');
  text.classList.remove('hidden');
  text.textContent=out||'ไม่พบกฎที่ตรงกับดวงนี้';
  copyBtn.disabled=!out;
}
function closeInterpretation(){
  document.getElementById('interp-backdrop')?.classList.add('hidden');
  document.getElementById('interp-modal')?.classList.add('hidden');
}
function _copyInterpretation(){
  const text=document.getElementById('interp-text')?.textContent||'';
  if(!text)return;
  navigator.clipboard.writeText(text)
    .then(()=>_showToast('คัดลอกคำทำนายแล้ว'))
    .catch(()=>{
      // fallback
      const ta=document.createElement('textarea');
      ta.value=text;document.body.appendChild(ta);
      ta.select();document.execCommand('copy');
      document.body.removeChild(ta);
      _showToast('คัดลอกคำทำนายแล้ว');
    });
}
